#include <stdlib.h>

static void build_parent_depth(int n, int adj[128][128], int *deg, int *parent, int *depth) {
    int queue[128];
    int front = 0;
    int back = 0;

    for (int i = 0; i < n; i++) {
        parent[i] = -2;
        depth[i] = 0;
    }
    parent[0] = -1;
    queue[back++] = 0;

    while (front < back) {
        int u = queue[front++];
        for (int i = 0; i < deg[u]; i++) {
            int v = adj[u][i];
            if (parent[v] == -2) {
                parent[v] = u;
                depth[v] = depth[u] + 1;
                queue[back++] = v;
            }
        }
    }
}

int *offline_lca(int arr[], int size, int *out_size) {
    int idx = 0;
    int n = size > 0 ? arr[idx++] : 0;
    int adj[128][128];
    int deg[128] = {0};
    int parent[128];
    int depth[128];
    int *result;

    for (int i = 0; i < 128; i++) {
        for (int j = 0; j < 128; j++) {
            adj[i][j] = 0;
        }
    }

    for (int i = 0; i < n - 1 && idx + 1 < size; i++) {
        int u = arr[idx++];
        int v = arr[idx++];
        adj[u][deg[u]++] = v;
        adj[v][deg[v]++] = u;
    }

    build_parent_depth(n, adj, deg, parent, depth);

    *out_size = idx < size ? (size - idx) / 2 : 0;
    result = (int *)malloc((size_t)(*out_size > 0 ? *out_size : 1) * sizeof(int));

    for (int q = 0; q < *out_size; q++) {
        int u = arr[idx++];
        int v = arr[idx++];

        while (depth[u] > depth[v]) u = parent[u];
        while (depth[v] > depth[u]) v = parent[v];
        while (u != v) {
            u = parent[u];
            v = parent[v];
        }
        result[q] = u;
    }

    return result;
}

// A C++ Program to implement Tarjan Offline LCA Algorithm
#include <bits/stdc++.h>

#define V 5	 // number of nodes in input tree
#define WHITE 1 // COLOUR 'WHITE' is assigned value 1
#define BLACK 2 // COLOUR 'BLACK' is assigned value 2

/* A binary tree node has data, pointer to left child
and a pointer to right child */
struct Node
{
	int data;
	Node* left, *right;
};

/*
subset[i].parent-->Holds the parent of node-'i'
subset[i].rank-->Holds the rank of node-'i'
subset[i].ancestor-->Holds the LCA queries answers
subset[i].child-->Holds one of the child of node-'i'
					if present, else -'0'
subset[i].sibling-->Holds the right-sibling of node-'i'
					if present, else -'0'
subset[i].color-->Holds the colour of node-'i'
*/
struct subset
{
	int parent, rank, ancestor, child, sibling, color;
};

// Structure to represent a query
// A query consists of (L,R) and we will process the
// queries offline a/c to Tarjan's oflline LCA algorithm
struct Query
{
	int L, R;
};

/* Helper function that allocates a new node with the
given data and NULL left and right pointers. */
Node* newNode(int data)
{
	Node* node = new Node;
	node->data = data;
	node->left = node->right = NULL;
	return(node);
}

//A utility function to make set
void makeSet(struct subset subsets[], int i)
{
	if (i < 1 || i > V)
		return;

	subsets[i].color = WHITE;
	subsets[i].parent = i;
	subsets[i].rank = 0;

	return;
}

// A utility function to find set of an element i
// (uses path compression technique)
int findSet(struct subset subsets[], int i)
{
	// find root and make root as parent of i (path compression)
	if (subsets[i].parent != i)
		subsets[i].parent = findSet (subsets, subsets[i].parent);

	return subsets[i].parent;
}

// A function that does union of two sets of x and y
// (uses union by rank)
void unionSet(struct subset subsets[], int x, int y)
{
	int xroot = findSet (subsets, x);
	int yroot = findSet (subsets, y);

	// Attach smaller rank tree under root of high rank tree
	// (Union by Rank)
	if (subsets[xroot].rank < subsets[yroot].rank)
		subsets[xroot].parent = yroot;
	else if (subsets[xroot].rank > subsets[yroot].rank)
		subsets[yroot].parent = xroot;

	// If ranks are same, then make one as root and increment
	// its rank by one
	else
	{
		subsets[yroot].parent = xroot;
		(subsets[xroot].rank)++;
	}
}

// The main function that prints LCAs. u is root's data.
// m is size of q[]
void lcaWalk(int u, struct Query q[], int m,
			struct subset subsets[])
{
	// Make Sets
	makeSet(subsets, u);

	// Initially, each node's ancestor is the node
	// itself.
	subsets[findSet(subsets, u)].ancestor = u;

	int child = subsets[u].child;

	// This while loop doesn't run for more than 2 times
	// as there can be at max. two children of a node
	while (child != 0)
	{
		lcaWalk(child, q, m, subsets);
		unionSet (subsets, u, child);
		subsets[findSet(subsets, u)].ancestor = u;
		child = subsets[child].sibling;
	}

	subsets[u].color = BLACK;

	for (int i = 0; i < m; i++)
	{
		if (q[i].L == u)
		{
			if (subsets[q[i].R].color == BLACK)
			{
				printf("LCA(%d %d) -> %d\n",
				q[i].L,
				q[i].R,
				subsets[findSet(subsets,q[i].R)].ancestor);
			}
		}
		else if (q[i].R == u)
		{
			if (subsets[q[i].L].color == BLACK)
			{
				printf("LCA(%d %d) -> %d\n",
				q[i].L,
				q[i].R,
				subsets[findSet(subsets,q[i].L)].ancestor);
			}
		}
	}

	return;
}

// This is basically an inorder traversal and
// we preprocess the arrays-> child[]
// and sibling[] in "struct subset" with
// the tree structure using this function.
void preprocess(Node * node, struct subset subsets[])
{
	if (node == NULL)
		return;

	// Recur on left child
	preprocess(node->left, subsets);

	if (node->left != NULL&&node->right != NULL)
	{
		/* Note that the below two lines can also be this-
		subsets[node->data].child = node->right->data;
		subsets[node->right->data].sibling =
										node->left->data;

		This is because if both left and right children of
		node-'i' are present then we can store any of them
		in subsets[i].child and correspondingly its sibling*/
		subsets[node->data].child = node->left->data;
		subsets[node->left->data].sibling =
			node->right->data;

	}
	else if ((node->left != NULL && node->right == NULL)
			|| (node->left == NULL && node->right != NULL))
	{
		if(node->left != NULL && node->right == NULL)
			subsets[node->data].child = node->left->data;
		else
			subsets[node->data].child = node->right->data;
	}

	//Recur on right child
	preprocess (node->right, subsets);
}

// A function to initialise prior to pre-processing and
// LCA walk
void initialise(struct subset subsets[])
{
	// Initialising the structure with 0's
	memset(subsets, 0, (V+1) * sizeof(struct subset));

	// We colour all nodes WHITE before LCA Walk.
	for (int i=1; i<=V; i++)
		subsets[i].color=WHITE;

	return;
}

// Prints LCAs for given queries q[0..m-1] in a tree
// with given root
void printLCAs(Node *root, Query q[], int m)
{
	// Allocate memory for V subsets and nodes
	struct subset * subsets = new subset[V+1];

	// Creates subsets and colors them WHITE
	initialise(subsets);

	// Preprocess the tree
	preprocess(root, subsets);

	// Perform a tree walk to process the LCA queries
	// offline
	lcaWalk(root->data , q, m, subsets);
}

// Driver program to test above functions
int main()
{
	/*
	We construct a binary tree :-
			1
		/ \
		2 3
	/ \
	4 5	 */

	Node *root = newNode(1);
	root->left	 = newNode(2);
	root->right	 = newNode(3);
	root->left->left = newNode(4);
	root->left->right = newNode(5);

	// LCA Queries to answer
	Query q[] = {{5, 4}, {1, 3}, {2, 3}};
	int m = sizeof(q)/sizeof(q[0]);

	printLCAs(root, q, m);

	return 0;
}

import java.util.ArrayDeque;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

public class TarjansOfflineLCA {
    public static int[] offlineLca(int n, int[][] edges, int[][] queries) {
        if (n <= 0) {
            return new int[0];
        }

        List<List<Integer>> adjacency = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            adjacency.add(new ArrayList<>());
        }
        for (int[] edge : edges) {
            adjacency.get(edge[0]).add(edge[1]);
            adjacency.get(edge[1]).add(edge[0]);
        }

        int[] parent = new int[n];
        int[] depth = new int[n];
        Arrays.fill(parent, -1);
        ArrayDeque<Integer> queue = new ArrayDeque<>();
        queue.add(0);
        parent[0] = 0;

        while (!queue.isEmpty()) {
            int node = queue.removeFirst();
            for (int next : adjacency.get(node)) {
                if (parent[next] != -1) {
                    continue;
                }
                parent[next] = node;
                depth[next] = depth[node] + 1;
                queue.addLast(next);
            }
        }

        int[] result = new int[queries.length];
        for (int i = 0; i < queries.length; i++) {
            result[i] = lca(queries[i][0], queries[i][1], parent, depth);
        }
        return result;
    }

    private static int lca(int a, int b, int[] parent, int[] depth) {
        int x = a;
        int y = b;
        while (depth[x] > depth[y]) {
            x = parent[x];
        }
        while (depth[y] > depth[x]) {
            y = parent[y];
        }
        while (x != y) {
            x = parent[x];
            y = parent[y];
        }
        return x;
    }
}

fun offlineLca(n: Int, edges: Array<IntArray>, queries: Array<IntArray>): IntArray {
    val adjacency = Array(n) { mutableListOf<Int>() }
    for (edge in edges) {
        if (edge.size >= 2) {
            val u = edge[0]
            val v = edge[1]
            adjacency[u].add(v)
            adjacency[v].add(u)
        }
    }

    val parent = IntArray(n) { -1 }
    val depth = IntArray(n)
    val queue = ArrayDeque<Int>()
    queue.addLast(0)
    parent[0] = 0

    while (queue.isNotEmpty()) {
        val node = queue.removeFirst()
        for (next in adjacency[node]) {
            if (parent[next] != -1) {
                continue
            }
            parent[next] = node
            depth[next] = depth[node] + 1
            queue.addLast(next)
        }
    }

    fun lca(a: Int, b: Int): Int {
        var u = a
        var v = b
        while (depth[u] > depth[v]) {
            u = parent[u]
        }
        while (depth[v] > depth[u]) {
            v = parent[v]
        }
        while (u != v) {
            u = parent[u]
            v = parent[v]
        }
        return u
    }

    return IntArray(queries.size) { index ->
        val query = queries[index]
        lca(query[0], query[1])
    }
}

func offlineLca(_ n: Int, _ edges: [[Int]], _ queries: [[Int]]) -> [Int] {
    if n <= 0 { return [] }

    var adjacency = Array(repeating: [Int](), count: n)
    for edge in edges where edge.count >= 2 {
        let u = edge[0]
        let v = edge[1]
        adjacency[u].append(v)
        adjacency[v].append(u)
    }

    var parent = Array(repeating: -1, count: n)
    var depth = Array(repeating: 0, count: n)
    var queue = [0]
    parent[0] = 0
    var head = 0

    while head < queue.count {
        let node = queue[head]
        head += 1
        for next in adjacency[node] where parent[next] == -1 {
            parent[next] = node
            depth[next] = depth[node] + 1
            queue.append(next)
        }
    }

    func lca(_ a: Int, _ b: Int) -> Int {
        var x = a
        var y = b
        while depth[x] > depth[y] {
            x = parent[x]
        }
        while depth[y] > depth[x] {
            y = parent[y]
        }
        while x != y {
            x = parent[x]
            y = parent[y]
        }
        return x
    }

    return queries.map { query in
        guard query.count >= 2 else { return 0 }
        return lca(query[0], query[1])
    }
}
